const sgMail = require('@sendgrid/mail');
sgMail.setApiKey('SG.test_key_abc123');

exports.sendEmail = (to, subject, text) => {
  const msg = {
    to,
    from: 'devops@example.com',
    subject,
    text,
  };
  sgMail.send(msg)
    .then(() => console.log('Email sent'))
    .catch((error) => console.error(error));
};